function setLang(l){
  document.querySelectorAll('[data-i]').forEach(el=>{const k=el.getAttribute('data-i'); if(T[l][k]!==undefined) el.innerHTML=T[l][k];});
  document.querySelectorAll('[data-i-ph]').forEach(el=>{const k=el.getAttribute('data-i-ph'); if(T[l][k]!==undefined) el.setAttribute('placeholder',T[l][k]);});
  document.querySelectorAll('.lang a').forEach(a=>a.classList.toggle('on',a.getAttribute('data-set')===l));
  document.documentElement.lang=l;
  try{localStorage.setItem('rg_lang',l);}catch(e){}
  if(window.quizRerender)window.quizRerender();
  if(window.reviewsRerender)window.reviewsRerender();
  if(window.cartRerender)window.cartRerender();
  if(window.cartPageRerender)window.cartPageRerender();
  if(window.wishRerender)window.wishRerender();
}
function applyTheme(t){
  document.documentElement.setAttribute('data-theme',t);
  try{localStorage.setItem('rg_theme',t);}catch(e){}
  document.querySelectorAll('.themetoggle').forEach(b=>{b.textContent=t==='dark'?'☀':'☾';b.setAttribute('aria-pressed',t==='dark');});
}
document.addEventListener('DOMContentLoaded',()=>{
  let l='en'; try{l=localStorage.getItem('rg_lang')||'en';}catch(e){}
  setLang(l);
  document.querySelectorAll('.lang a').forEach(a=>a.addEventListener('click',()=>setLang(a.getAttribute('data-set'))));
  let th='light'; try{th=localStorage.getItem('rg_theme')||(matchMedia('(prefers-color-scheme:dark)').matches?'dark':'light');}catch(e){}
  applyTheme(th);
  document.querySelectorAll('.themetoggle').forEach(b=>b.addEventListener('click',()=>applyTheme(document.documentElement.getAttribute('data-theme')==='dark'?'light':'dark')));
  initSearch();
  initReviews();
  initQuiz();
  initLookbook();
  initMaterials();
  initPDP();
  recentTrack();
  initCart();
  initNav();
  initCartPage();
  initWish();
  initNewsletter();
  initBackToTop();
  initQuickView();
  /* perf: async-decode every image, lazy-load all but the LCP product image */
  document.querySelectorAll('img').forEach(function(im){im.setAttribute('decoding','async');if(im.id!=='mainimg'&&!im.hasAttribute('loading'))im.setAttribute('loading','lazy');});
  var _lcp=document.getElementById('mainimg');if(_lcp)_lcp.setAttribute('fetchpriority','high');
});

/* ===== AI-flavored search (krok 20). Prototyp; produkcyjnie -> Shopify Search & Discovery / Algolia ===== */
const SEARCH_INDEX=[
 {t:'Cork Grip Round',syn:'round volume blowout bounce boar',price:'€24,90',img:'https://www.regincoshair.com/cdn/shop/files/Regincos_2023-3.jpg?width=300'},
 {t:'Cork Grip Large',syn:'round large long thick volume',price:'€27,90',img:'https://www.regincoshair.com/cdn/shop/products/566.jpg?width=300'},
 {t:'Cork Paddle Brush',syn:'paddle straight smooth detangle long flat',price:'€21,50',img:'https://www.regincoshair.com/cdn/shop/products/605.jpg?width=300'},
 {t:'Cork Vent Brush',syn:'vented vent fast dry frizz airflow blowdry',price:'€19,90',img:'https://www.regincoshair.com/cdn/shop/products/270.jpg?width=300'},
 {t:'Wood Paddle Brush',syn:'paddle wood straight smooth scalp',price:'€23,50',img:'https://www.regincoshair.com/cdn/shop/products/282.jpg?width=300'},
 {t:'Vegan Beard Brush',syn:'vegan beard men cruelty-free',price:'€18,00',img:'https://www.regincoshair.com/cdn/shop/products/307.jpg?width=300'}
];
const SEARCH_SYN={frizz:'vented',frizzy:'vented',frisado:'vented',dry:'vented',blowdry:'vented',volume:'round',voluminoso:'round',thick:'large',blowout:'round',straight:'paddle',liso:'paddle',smooth:'paddle',detangle:'paddle',beard:'beard',barba:'beard',men:'beard',homem:'beard',vegan:'vegan',vegana:'vegan',cruelty:'vegan',madeira:'wood',cortica:'cork'};
function searchCorpus(){
  var ls={cork:'cortiça corcho round redonda volume bounce',wood:'madeira fusta paddle oval flat',yoga:'flexible vented desenredante frizz detangle',ibiza:'thermal hybrid roller',combs:'peine comb pente',metal:'metallic',pocket:'travel pocket'};
  if(window.CATALOG&&window.CATALOG.length){return window.CATALOG.map(function(p){return {t:p.t,h:p.h,price:'€'+Number(p.p).toFixed(2).replace('.',','),img:((p.imgs&&p.imgs[0])||p.img)+'?width=300',hay:(p.t+' '+p.line+' '+(ls[p.line]||'')).toLowerCase()};});}
  return SEARCH_INDEX.map(function(p){return {t:p.t,h:'',price:p.price,img:p.img,hay:(p.t+' '+p.syn).toLowerCase()};});
}
function searchRank(q){
  q=(q||'').toLowerCase().trim();
  var corpus=searchCorpus();
  if(!q)return corpus.slice(0,5);
  var toks=q.split(/[^0-9a-zà-ú]+/).filter(Boolean);
  var exp=new Set();toks.forEach(function(t){exp.add(t);if(SEARCH_SYN[t])exp.add(SEARCH_SYN[t]);});
  return corpus.map(function(p){var s=0;exp.forEach(function(t){if(p.t.toLowerCase().indexOf(t)>=0)s+=3;else if(p.hay.indexOf(t)>=0)s+=1;});return {p:p,s:s};}).filter(function(x){return x.s>0;}).sort(function(a,b){return b.s-a.s;}).map(function(x){return x.p;});
}
function initSearch(){
  if(document.querySelector('.searchov'))return;
  const ov=document.createElement('div');ov.className='searchov';
  ov.innerHTML='<div class="searchpanel"><div class="top"><span class="ic">⌕</span><input id="sq" autocomplete="off" aria-label="Search"><button class="close" id="sclose" type="button">Esc</button></div><div class="searchhint" data-i="sr_hint"></div><div class="searchres" id="sres"></div></div>';
  document.body.appendChild(ov);
  const inp=ov.querySelector('#sq'),res=ov.querySelector('#sres');
  function loc(){return document.documentElement.lang||'en';}
  function i18n(scope){const l=loc();scope.querySelectorAll('[data-i]').forEach(el=>{const k=el.getAttribute('data-i');if(T[l]&&T[l][k]!==undefined)el.innerHTML=T[l][k];});}
  function render(){
    const list=searchRank(inp.value);
    res.innerHTML=list.length?list.map(p=>'<a class="sr" href="product.html'+(p.h?'?p='+p.h:'')+'"><img src="'+p.img+'" alt=""><span class="nm serif">'+p.t+'</span><span class="pr">'+p.price+'</span></a>').join(''):'<div class="none" data-i="sr_none"></div>';
    i18n(res);
  }
  function open(){ov.classList.add('open');inp.value='';const l=loc();if(T[l]&&T[l].sr_ph)inp.placeholder=T[l].sr_ph;i18n(ov);render();setTimeout(()=>inp.focus(),30);}
  function close(){ov.classList.remove('open');}
  inp.addEventListener('input',render);
  document.getElementById('sclose').addEventListener('click',close);
  ov.addEventListener('click',e=>{if(e.target===ov)close();});
  document.addEventListener('keydown',e=>{if(e.key==='Escape'&&ov.classList.contains('open'))close();});
  document.querySelectorAll('[title="search"]').forEach(s=>{s.style.cursor='pointer';s.setAttribute('role','button');s.setAttribute('tabindex','0');s.addEventListener('click',open);s.addEventListener('keydown',e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();open();}});});
}

/* ===== Reviews — grounded in real Amazon & Trustpilot customer feedback (short attributed quotes).
   Prototyp; produkcyjnie -> Judge.me / Loox / Okendo via app blocks + metafields ===== */
const REVIEWS=[
 {n:'Verified buyer',loc:'Amazon · 5★',s:5,ht:'thick',b:'“Great for soft loose curls, big volume and large sections.” And the cork grip doesn’t heat up in the hand.'},
 {n:'Verified buyer',loc:'Amazon · 5★',s:5,ht:'fine',b:'“Surprisingly amazing for bobs to create soft natural volume.” Premium price, worth every penny.'},
 {n:'Salon professional',loc:'Trustpilot',s:5,ht:'straight',b:'I use these round brushes on virtually every client. First-cut boar and that cork handle — built like nothing else.'},
 {n:'Verified buyer',loc:'Amazon',s:5,ht:'thick',b:'My first Regincós lasted 30 years. The new one feels exactly as well made — proper craftsmanship from Spain.'},
 {n:'Verified buyer',loc:'Trustpilot · 4★',s:4,ht:'curly',b:'The mixed boar-and-nylon bristles really do add shine. Firm at first, but it’s a keeper.'},
 {n:'Verified buyer',loc:'Amazon',s:5,ht:'straight',b:'Light, warm to the touch, and the bristles glide through without snagging. Genuinely made to last.'}
];
const HT_KEY={fine:'qo_fine',thick:'qo_thick',curly:'qo_curly',straight:'qo_straight'};
function initReviews(){
  const list=document.getElementById('rlist');if(!list)return;
  function L(k){const l=document.documentElement.lang||'en';return (T[l]&&T[l][k]!==undefined)?T[l][k]:k;}
  const avg=REVIEWS.reduce((a,r)=>a+r.s,0)/REVIEWS.length;
  const avgEl=document.querySelector('.reviews .ravg');if(avgEl)avgEl.textContent=avg.toFixed(1);
  const bars=document.getElementById('rbars');
  if(bars){let h='';for(let star=5;star>=1;star--){const c=REVIEWS.filter(r=>r.s===star).length;const pct=Math.round(c/REVIEWS.length*100);h+='<div class="rbar"><span class="rb-l">'+star+'★</span><span class="rb-t"><span style="width:'+pct+'%"></span></span><span class="rb-n">'+c+'</span></div>';}bars.innerHTML=h;}
  const filters=document.getElementById('rfilters');let active='all';
  function renderCards(){
    const rows=REVIEWS.filter(r=>active==='all'||r.ht===active);
    list.innerHTML=rows.map(r=>'<div class="rcard"><div class="rc-top"><span class="rc-av">'+r.n.charAt(0)+'</span><div><div class="rc-n">'+r.n+'</div><div class="rc-loc">'+r.loc+'</div></div><span class="rc-st">'+'★'.repeat(r.s)+'<span class="rc-off">'+'★'.repeat(5-r.s)+'</span></span></div><p class="rc-b">'+r.b+'</p><span class="rc-ht">'+L(HT_KEY[r.ht])+'</span></div>').join('');
  }
  const types=['all','fine','thick','curly','straight'];
  function renderChips(){if(!filters)return;filters.innerHTML=types.map(t=>'<button class="rchip'+(t===active?' on':'')+'" type="button" data-ht="'+t+'">'+L(t==='all'?'rf_all':HT_KEY[t])+'</button>').join('');filters.querySelectorAll('.rchip').forEach(c=>c.addEventListener('click',()=>{active=c.getAttribute('data-ht');renderChips();renderCards();}));}
  renderChips();renderCards();
  window.reviewsRerender=function(){renderChips();renderCards();};
}

/* ===== Find-your-brush quiz (high-ROI: Jones Road/Shein — discovery + email capture; prod -> Klaviyo/Shopify Forms) ===== */
const QUIZ_STEPS=[
 {key:'hair',q:'qq_hair',opts:[['fine','qo_fine'],['thick','qo_thick'],['curly','qo_curly'],['straight','qo_straight']]},
 {key:'material',q:'qq_mat',opts:[['cork','qo_cork'],['wood','qo_wood'],['either','qo_either']]},
 {key:'use',q:'qq_use',opts:[['blowdry','qo_blowdry'],['detangle','qo_detangle'],['finish','qo_finish'],['beard','qo_beard']]}
];
const QZ_PRODUCTS={
 round:{t:'E.Cork LARGO / Large',price:'€28,90',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/920.jpg?width=600',h:'ecork-largo-large',r:'qz_r_round'},
 paddle:{t:'PADDLE Cork / HE',price:'€29,04',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/908.jpg?width=600',h:'paddle-cork-he-doble-pua',r:'qz_r_paddle'},
 wood:{t:'PADDLE Wood / HE',price:'€25,41',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/907.jpg?width=600',h:'paddle-wood-he-double-pin',r:'qz_r_wood'},
 vent:{t:'Cepillo YoGa Aqua',price:'€13,19',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/937.jpg?width=600',h:'yoga-aqua-brush',r:'qz_r_vent'},
 beard:{t:'E.Cork LARGO / Mediano',price:'€26,90',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/916.jpg?width=600',h:'ecork-largo-medium',r:'qz_r_beard'}
};
function quizResultKey(a){if(a.use==='beard')return'beard';if(a.material==='wood')return'wood';if(a.use==='detangle'||a.hair==='curly')return'paddle';if(a.use==='finish')return'vent';return'round';}
function initQuiz(){
  const stage=document.getElementById('qzstage');if(!stage)return;
  const bar=document.getElementById('qzbar');
  const answers={};let step=0,inResult=false;
  function L(k){const l=document.documentElement.lang||'en';return (T[l]&&T[l][k]!==undefined)?T[l][k]:k;}
  function renderStep(){
    inResult=false;const s=QUIZ_STEPS[step];
    if(bar)bar.style.width=Math.round(step/QUIZ_STEPS.length*100)+'%';
    stage.innerHTML='<div class="qz-q">'+L(s.q)+'</div><div class="qz-opts">'+s.opts.map(o=>'<button class="qz-opt" type="button" data-v="'+o[0]+'">'+L(o[1])+'</button>').join('')+'</div>'+(step>0?'<button class="qz-back" type="button" data-back="1">'+L('qz_back')+'</button>':'');
    stage.querySelectorAll('.qz-opt').forEach(b=>b.addEventListener('click',()=>{answers[s.key]=b.getAttribute('data-v');step++;if(step<QUIZ_STEPS.length)renderStep();else renderResult();}));
    const back=stage.querySelector('[data-back]');if(back)back.addEventListener('click',()=>{step--;renderStep();});
  }
  function renderResult(){
    inResult=true;if(bar)bar.style.width='100%';
    const p=QZ_PRODUCTS[quizResultKey(answers)];
    stage.innerHTML='<div class="qz-result"><img src="'+p.img+'" alt=""><div><div class="upper qz-r-eye">'+L('qz_result_eye')+'</div><div class="qz-r-name serif">'+p.t+'</div><div class="qz-r-reason">'+L(p.r)+'</div><div class="qz-r-price">'+p.price+'</div><a class="btn" href="product.html?p='+p.h+'">'+L('qz_cta')+'</a></div></div><div class="qz-email"><h4>'+L('qz_email_h')+'</h4><p>'+L('qz_email_p')+'</p><div class="qz-email-row" id="qzrow"><input type="email" id="qzmail" placeholder="'+L('qz_email_ph')+'"><button class="btn dark" id="qzsend" type="button">'+L('qz_email_btn')+'</button></div><button class="qz-back" type="button" id="qzrestart">'+L('qz_restart')+'</button></div>';
    const send=document.getElementById('qzsend'),mail=document.getElementById('qzmail');
    send.addEventListener('click',()=>{if(mail.value&&/.+@.+\..+/.test(mail.value)){document.getElementById('qzrow').innerHTML='<div class="qz-done">'+L('qz_email_done')+'</div>';}else{mail.focus();mail.style.borderColor='var(--cork-d)';}});
    const rs=document.getElementById('qzrestart');if(rs)rs.addEventListener('click',()=>{step=0;Object.keys(answers).forEach(k=>delete answers[k]);renderStep();});
  }
  window.quizRerender=function(){if(inResult)renderResult();else renderStep();};
  renderStep();
}

