/* ===== Cart drawer (prototype — localStorage; produkcyjnie -> Shopify AJAX cart) ===== */
var FREE_SHIP=49, _toastTmr;
function cartLang(){return document.documentElement.lang||'en';}
function cartT(k){var l=cartLang();return (T[l]&&T[l][k]!==undefined)?T[l][k]:(T.en[k]!==undefined?T.en[k]:k);}
function eurFmt(n){return '€'+Number(n||0).toFixed(2).replace('.',',');}
function cartGet(){try{return JSON.parse(localStorage.getItem('rg_cart')||'[]');}catch(e){return [];}}
function cartSave(c){try{localStorage.setItem('rg_cart',JSON.stringify(c));}catch(e){}cartBadge();cartRender();if(window.cartPageRerender)window.cartPageRerender();}
function cartCount(){return cartGet().reduce(function(a,x){return a+(x.q||1);},0);}
function cartTotal(){return cartGet().reduce(function(a,x){return a+(Number(x.p)||0)*(x.q||1);},0);}
function cartBadge(){var n=cartCount();document.querySelectorAll('[title="cart"]').forEach(function(s){s.textContent='⛒ '+n;s.classList.toggle('has',n>0);});}
function cartImg(u){u=u||'';return u+((u&&u.indexOf('?')<0)?'?width=160':'');}
function cartAdd(item,srcEl){
  if(!item||item.p==null||!(Number(item.p)>0))return;
  if(srcEl)flyToCart(srcEl,item.img);
  var c=cartGet();var key=item.h+'|'+(item.v||'');
  var ex=c.find(function(x){return (x.h+'|'+(x.v||''))===key;});
  if(ex){ex.q=(ex.q||1)+(item.q||1);}else{c.push({h:item.h,t:item.t,p:Number(item.p),img:item.img,v:item.v||'',q:item.q||1});}
  cartSave(c);cartToast(cartT('cart_added'));cartOpen();
}
function cartSetQty(i,q){var c=cartGet();if(!c[i])return;c[i].q=Math.max(1,q);cartSave(c);}
function cartRemove(i){var c=cartGet();c.splice(i,1);cartSave(c);}
function cartEnsureDOM(){
  if(document.getElementById('cartDrawer'))return;
  var ov=document.createElement('div');ov.className='cart-ov';ov.id='cartOv';ov.hidden=true;ov.addEventListener('click',cartClose);
  var d=document.createElement('aside');d.className='cart-dr';d.id='cartDrawer';d.setAttribute('aria-hidden','true');d.setAttribute('aria-label','Cart');d.setAttribute('role','dialog');
  d.innerHTML='<div class="cd-top"><span class="cd-ttl serif"></span><button class="cd-x" type="button" aria-label="Close">✕</button></div>'+
    '<div class="cd-ship" id="cdShip"></div>'+
    '<div class="cd-items" id="cdItems"></div>'+
    '<div class="cd-foot"><div class="cd-sub"><span class="cd-sublab"></span><span id="cdTotal"></span></div><button class="btn block" id="cdCheckout" type="button"></button><div class="cd-note"></div></div>';
  document.body.appendChild(ov);document.body.appendChild(d);
  d.querySelector('.cd-x').addEventListener('click',cartClose);
  d.querySelector('#cdCheckout').addEventListener('click',function(){if(cartGet().length)window.location.href='cart.html';});
  d.querySelector('#cdItems').addEventListener('click',function(e){
    var b=e.target.closest('[data-act]');if(!b)return;
    var i=parseInt(b.getAttribute('data-i2'),10);var act=b.getAttribute('data-act');var c=cartGet();if(!c[i]&&act!=='rm')return;
    if(act==='inc')cartSetQty(i,(c[i].q||1)+1);
    else if(act==='dec')cartSetQty(i,(c[i].q||1)-1);
    else if(act==='rm')cartRemove(i);
  });
  if(!document.getElementById('cartToast')){var t=document.createElement('div');t.className='cart-toast';t.id='cartToast';t.setAttribute('role','status');document.body.appendChild(t);}
  window.cartRerender=cartRender;
}
function cartRender(){
  var d=document.getElementById('cartDrawer');if(!d)return;
  var c=cartGet();
  d.querySelector('.cd-ttl').textContent=cartT('cart_title');
  d.querySelector('.cd-sublab').textContent=cartT('cart_sub');
  d.querySelector('.cd-note').textContent=cartT('cart_note');
  d.querySelector('#cdCheckout').textContent=cartT('cart_checkout');
  var items=d.querySelector('#cdItems'),ship=d.querySelector('#cdShip'),foot=d.querySelector('.cd-foot');
  if(!c.length){
    items.innerHTML='<div class="cd-empty"><p>'+cartT('cart_empty')+'</p><a class="btn" href="collection.html">'+cartT('cart_empty_cta')+'</a></div>';
    ship.style.display='none';foot.style.display='none';return;
  }
  foot.style.display='';ship.style.display='';
  items.innerHTML=c.map(function(x,i){
    return '<div class="cd-item"><img src="'+cartImg(x.img)+'" alt="" loading="lazy"><div class="cd-mid"><div class="cd-n serif">'+x.t+'</div>'+(x.v?'<div class="cd-v">'+x.v+'</div>':'')+'<div class="cd-qr"><div class="cd-qty"><button type="button" data-act="dec" data-i2="'+i+'" aria-label="−">−</button><span>'+x.q+'</span><button type="button" data-act="inc" data-i2="'+i+'" aria-label="+">+</button></div><button class="cd-rm" type="button" data-act="rm" data-i2="'+i+'">'+cartT('cart_remove')+'</button></div></div><div class="cd-p">'+eurFmt(Number(x.p)*x.q)+'</div></div>';
  }).join('');
  var total=cartTotal(),pct=Math.min(100,Math.round(total/FREE_SHIP*100));
  if(total>=FREE_SHIP){ship.innerHTML='<div class="cd-shiptxt ok">✓ '+cartT('cart_ship_free')+'</div><div class="cd-bar"><i style="width:100%"></i></div>';}
  else{ship.innerHTML='<div class="cd-shiptxt">'+cartT('cart_ship_a')+' <b>'+eurFmt(FREE_SHIP-total)+'</b> '+cartT('cart_ship_b')+'</div><div class="cd-bar"><i style="width:'+pct+'%"></i></div>';}
  d.querySelector('#cdTotal').textContent=eurFmt(total);
}
function cartOpen(){cartEnsureDOM();cartRender();var d=document.getElementById('cartDrawer'),ov=document.getElementById('cartOv');ov.hidden=false;void d.offsetWidth;d.classList.add('show');ov.classList.add('show');d.setAttribute('aria-hidden','false');document.body.style.overflow='hidden';}
function cartClose(){var d=document.getElementById('cartDrawer'),ov=document.getElementById('cartOv');if(!d)return;d.classList.remove('show');ov.classList.remove('show');d.setAttribute('aria-hidden','true');document.body.style.overflow='';setTimeout(function(){ov.hidden=true;},320);}
function cartToast(msg){cartEnsureDOM();var t=document.getElementById('cartToast');if(!t)return;t.textContent=msg;t.classList.add('show');clearTimeout(_toastTmr);_toastTmr=setTimeout(function(){t.classList.remove('show');},1800);}
function _catProd(h){return (h&&window.CATALOG)?window.CATALOG.find(function(x){return x.h===h;}):null;}
/* ===== Fly-to-cart: ghost image arcs from source to the cart icon, then badge bumps ===== */
function bumpCart(){document.querySelectorAll('[title="cart"]').forEach(function(c){c.classList.remove('bump');void c.offsetWidth;c.classList.add('bump');setTimeout(function(){c.classList.remove('bump');},640);});}
function flyToCart(sourceEl,imgUrl){
  try{
    var cart=document.querySelector('[title="cart"]');if(!cart)return;
    if(!sourceEl||!imgUrl||matchMedia('(prefers-reduced-motion:reduce)').matches){bumpCart();return;}
    var s=sourceEl.getBoundingClientRect();if(!s.width||!s.height){bumpCart();return;}
    var c=cart.getBoundingClientRect();
    var ghost=document.createElement('img');ghost.src=cartImg(imgUrl);ghost.alt='';
    ghost.style.cssText='position:fixed;left:'+s.left+'px;top:'+s.top+'px;width:'+s.width+'px;height:'+s.height+'px;object-fit:cover;border-radius:8px;z-index:120;pointer-events:none;box-shadow:0 12px 30px rgba(20,15,10,.28);transition:transform .62s cubic-bezier(.5,-0.18,.3,1),opacity .62s ease-in;will-change:transform,opacity';
    document.body.appendChild(ghost);void ghost.offsetWidth;
    var dx=(c.left+c.width/2)-(s.left+s.width/2),dy=(c.top+c.height/2)-(s.top+s.height/2);
    ghost.style.transform='translate('+dx+'px,'+dy+'px) scale(.12)';ghost.style.opacity='0.35';
    setTimeout(function(){ghost.remove();bumpCart();},630);
  }catch(e){bumpCart();}
}
/* ===== Full cart page (/cart) — shares localStorage + cart helpers with the drawer ===== */
function renderCartPage(){
  var wrap=document.getElementById('cartpage');if(!wrap)return;
  var ttl=wrap.querySelector('[data-i="cart_title"]');if(ttl)ttl.textContent=cartT('cart_title');
  var grid=document.getElementById('cpGrid');if(!grid)return;
  var c=cartGet();
  if(!c.length){grid.innerHTML='<div class="cp-empty"><p>'+cartT('cart_empty')+'</p><a class="btn" href="collection.html">'+cartT('cart_empty_cta')+'</a></div>';return;}
  var items=c.map(function(x,i){return '<div class="cp-item"><img src="'+cartImg(x.img)+'" alt="" loading="lazy"><div class="cp-mid"><div class="cp-n serif">'+x.t+'</div>'+(x.v?'<div class="cp-v">'+x.v+'</div>':'')+'<button class="cp-rm" type="button" data-act="rm" data-i2="'+i+'">'+cartT('cart_remove')+'</button></div><div class="cp-qty"><button type="button" data-act="dec" data-i2="'+i+'" aria-label="−">−</button><span>'+x.q+'</span><button type="button" data-act="inc" data-i2="'+i+'" aria-label="+">+</button></div><div class="cp-p">'+eurFmt(Number(x.p)*x.q)+'</div></div>';}).join('');
  var total=cartTotal(),pct=Math.min(100,Math.round(total/FREE_SHIP*100));
  var ship=total>=FREE_SHIP?'<div class="cd-shiptxt ok">✓ '+cartT('cart_ship_free')+'</div><div class="cd-bar"><i style="width:100%"></i></div>':'<div class="cd-shiptxt">'+cartT('cart_ship_a')+' <b>'+eurFmt(FREE_SHIP-total)+'</b> '+cartT('cart_ship_b')+'</div><div class="cd-bar"><i style="width:'+pct+'%"></i></div>';
  grid.innerHTML='<div class="cp-items">'+items+'</div><aside class="cp-sum"><div class="cp-ship">'+ship+'</div><div class="cp-row"><span>'+cartT('cart_sub')+'</span><span class="cp-total">'+eurFmt(total)+'</span></div><button class="btn block" type="button" id="cpCheckout">'+cartT('cart_checkout')+'</button><a class="cp-cont" href="collection.html">'+cartT('cart_empty_cta')+'</a><div class="cp-note">'+cartT('cart_note')+'</div></aside>';
  var co=document.getElementById('cpCheckout');if(co)co.addEventListener('click',function(){cartToast(cartT('cart_note'));});
}
function initCartPage(){
  var wrap=document.getElementById('cartpage');if(!wrap)return;
  window.cartPageRerender=renderCartPage;
  var grid=document.getElementById('cpGrid');
  if(grid)grid.addEventListener('click',function(e){var b=e.target.closest('[data-act]');if(!b)return;var i=parseInt(b.getAttribute('data-i2'),10);var act=b.getAttribute('data-act');var cc=cartGet();if(!cc[i]&&act!=='rm')return;if(act==='inc')cartSetQty(i,(cc[i].q||1)+1);else if(act==='dec')cartSetQty(i,(cc[i].q||1)-1);else if(act==='rm')cartRemove(i);});
  renderCartPage();
}
/* ===== Quick view — modal product preview from catalog (delegated trigger) ===== */
var _qvHandle='',_qvVariant='';
function qvEnsureDOM(){
  if(document.getElementById('qvm'))return;
  var m=document.createElement('div');m.className='qvm';m.id='qvm';m.hidden=true;m.setAttribute('role','dialog');m.setAttribute('aria-label','Quick view');
  m.innerHTML='<div class="qvm-card"><button class="qvm-x" type="button" aria-label="Close">✕</button><div class="qvm-img"><img id="qvmImg" src="" alt=""></div><div class="qvm-info"><div class="upper kick" id="qvmLine"></div><h3 class="serif" id="qvmTitle"></h3><div class="qvm-price" id="qvmPrice"></div><p class="qvm-desc" id="qvmDesc"></p><div class="qvm-opts" id="qvmOpts"></div><div class="qvm-actions"><button class="btn block" id="qvmAdd" type="button"></button><a class="qvm-link" id="qvmLink"></a></div></div></div>';
  document.body.appendChild(m);
  m.addEventListener('click',function(e){if(e.target===m)qvClose();});
  m.querySelector('.qvm-x').addEventListener('click',qvClose);
  document.getElementById('qvmOpts').addEventListener('click',function(e){var b=e.target.closest('button');if(!b)return;document.querySelectorAll('#qvmOpts button').forEach(function(x){x.classList.remove('on');});b.classList.add('on');_qvVariant=b.textContent.trim();});
  document.getElementById('qvmAdd').addEventListener('click',function(){var p=_catProd(_qvHandle);if(!p)return;cartAdd({h:p.h,t:p.t,p:p.p,img:(p.imgs&&p.imgs[0])||p.img,v:_qvVariant,q:1},document.getElementById('qvmImg'));qvClose();});
  document.addEventListener('keydown',function(e){if(e.key==='Escape')qvClose();});
}
function qvOpen(h){
  var p=_catProd(h);if(!p)return;
  qvEnsureDOM();
  _qvHandle=h;_qvVariant=(p.v&&p.v.length)?p.v[0]:'';
  var l=document.documentElement.lang||'en',img=(p.imgs&&p.imgs[0])||p.img;
  var im=document.getElementById('qvmImg');im.src=img+'?width=800';im.alt=p.t;
  document.getElementById('qvmLine').textContent=p.line?p.line.charAt(0).toUpperCase()+p.line.slice(1):'';
  document.getElementById('qvmTitle').textContent=p.t;
  document.getElementById('qvmPrice').textContent='€'+Number(p.p).toFixed(2).replace('.',',');
  var desc=document.getElementById('qvmDesc');desc.textContent=p.d?p.d.slice(0,170):'';desc.style.display=p.d?'':'none';
  var opts=document.getElementById('qvmOpts');
  if(p.v&&p.v.length){opts.innerHTML=p.v.map(function(v,i){return '<button type="button" class="'+(i===0?'on':'')+'">'+v+'</button>';}).join('');opts.style.display='';}else{opts.innerHTML='';opts.style.display='none';}
  document.getElementById('qvmAdd').textContent=(T[l]&&T[l].addcart)||'Add to cart';
  var link=document.getElementById('qvmLink');link.href='product.html?p='+h;link.textContent=(T[l]&&T[l].qv_view)||'View full details';
  var m=document.getElementById('qvm');m.hidden=false;void m.offsetWidth;m.classList.add('show');document.body.style.overflow='hidden';
}
function qvClose(){var m=document.getElementById('qvm');if(!m)return;m.classList.remove('show');document.body.style.overflow='';setTimeout(function(){m.hidden=true;},250);}
function initQuickView(){document.addEventListener('click',function(e){var b=e.target.closest('.qv[data-qv]');if(!b)return;e.preventDefault();e.stopPropagation();qvOpen(b.getAttribute('data-qv'));});}
/* ===== Shared product-card markup (recently-viewed + related; works with delegated add/wish) ===== */
function prodCardHTML(p){
  var nm=p.t,price='€'+Number(p.p).toFixed(2).replace('.',',');
  return '<a class="prod" href="product.html?p='+p.h+'" data-price="'+p.p+'"><div class="ph"><img src="'+((p.imgs&&p.imgs[0])||p.img)+'?width=600" alt="'+nm.replace(/"/g,'')+'" loading="lazy"><button class="qv" type="button" data-qv="'+p.h+'" aria-label="Quick view">⤢</button><button class="wish'+((window.wishHas&&wishHas(p.h))?' on':'')+'" type="button" data-h="'+p.h+'" aria-label="Save to wishlist">♡</button><span class="add" data-i="addcart"></span></div><h4 class="serif">'+nm+'</h4><div class="px">'+price+'</div></a>';
}
function _fillCardI18n(grid){var l=document.documentElement.lang||'en';grid.querySelectorAll('[data-i]').forEach(function(el){var k=el.getAttribute('data-i');if(T[l]&&T[l][k]!==undefined)el.innerHTML=T[l][k];});}
/* ===== Related products (PDP) — real, from the same line in the catalog ===== */
function renderRelated(p){
  var grid=document.getElementById('relatedGrid');if(!grid||!p||!window.CATALOG)return;
  var rel=window.CATALOG.filter(function(x){return x.line===p.line&&x.h!==p.h;});
  if(rel.length<4)window.CATALOG.forEach(function(x){if(x.h!==p.h&&rel.indexOf(x)<0&&rel.length<8)rel.push(x);});
  rel=rel.slice(0,4);
  if(!rel.length)return;
  grid.innerHTML=rel.map(prodCardHTML).join('');
  _fillCardI18n(grid);
}
/* ===== Recently viewed (PDP) — localStorage, renders previously-viewed products ===== */
function recentTrack(){
  var h=new URLSearchParams(location.search).get('p');if(!h)return;
  var rec=[];try{rec=JSON.parse(localStorage.getItem('rg_recent')||'[]');}catch(e){}
  var prev=rec.slice();
  rec=rec.filter(function(x){return x!==h;});rec.unshift(h);rec=rec.slice(0,12);
  try{localStorage.setItem('rg_recent',JSON.stringify(rec));}catch(e){}
  var sec=document.getElementById('recently'),grid=document.getElementById('recentGrid');
  if(!sec||!grid||!window.CATALOG)return;
  var items=prev.filter(function(x){return x!==h;}).map(function(x){return window.CATALOG.find(function(p){return p.h===x;});}).filter(Boolean).slice(0,4);
  if(!items.length)return;
  grid.innerHTML=items.map(prodCardHTML).join('');
  _fillCardI18n(grid);
  sec.hidden=false;
}
/* ===== Newsletter band (injected before footer; 10%-off email capture, localStorage) ===== */
function initNewsletter(){
  var foot=document.querySelector('footer');
  if(!foot||!document.querySelector('footer .fcols')||document.getElementById('nlband'))return;
  var subbed=false;try{subbed=!!localStorage.getItem('rg_sub');}catch(e){}
  var band=document.createElement('section');band.className='nlband';band.id='nlband';
  band.innerHTML='<div class="wrap nl-in"><div class="nl-txt"><div class="upper eyebrow" data-i="nl_eye"></div><div class="h2 serif" data-i="nl_h"></div><p data-i="nl_p"></p></div><form class="nl-form" id="nlform" novalidate><input type="email" id="nlemail" required autocomplete="email" data-i-ph="nl_ph" aria-label="Email"><button class="btn dark" type="submit" data-i="nl_btn"></button></form><div class="nl-done" id="nldone" hidden data-i="nl_done"></div></div>';
  foot.parentNode.insertBefore(band,foot);
  var l=document.documentElement.lang||'en';
  band.querySelectorAll('[data-i]').forEach(function(el){var k=el.getAttribute('data-i');if(T[l]&&T[l][k]!==undefined)el.innerHTML=T[l][k];});
  band.querySelectorAll('[data-i-ph]').forEach(function(el){var k=el.getAttribute('data-i-ph');if(T[l]&&T[l][k]!==undefined)el.setAttribute('placeholder',T[l][k]);});
  var form=band.querySelector('#nlform'),done=band.querySelector('#nldone'),em=band.querySelector('#nlemail');
  function showDone(){form.hidden=true;done.hidden=false;}
  if(subbed)showDone();
  form.addEventListener('submit',function(e){e.preventDefault();if(!em.value||!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(em.value)){em.classList.add('nl-err');em.focus();return;}em.classList.remove('nl-err');try{localStorage.setItem('rg_sub',em.value);}catch(e){}showDone();});
}
/* ===== Back-to-top button ===== */
function initBackToTop(){
  if(document.getElementById('toTop'))return;
  var b=document.createElement('button');b.id='toTop';b.className='totop';b.type='button';b.setAttribute('aria-label','Back to top');b.innerHTML='↑';
  document.body.appendChild(b);
  var rm=matchMedia('(prefers-reduced-motion:reduce)').matches;
  b.addEventListener('click',function(){window.scrollTo({top:0,behavior:rm?'auto':'smooth'});});
  var onScroll=function(){b.classList.toggle('show',window.scrollY>600);};
  window.addEventListener('scroll',onScroll,{passive:true});onScroll();
}
/* ===== Wishlist (♡) — localStorage, drawer, heart toggles (delegated, survives re-renders) ===== */
function wishGet(){try{return JSON.parse(localStorage.getItem('rg_wish')||'[]');}catch(e){return [];}}
function wishSave(w){try{localStorage.setItem('rg_wish',JSON.stringify(w));}catch(e){}wishBadge();syncWishButtons();if(document.getElementById('wishDrawer'))wishRender();}
function wishHas(h){return wishGet().some(function(x){return x.h===h;});}
function wishToggle(item){var w=wishGet();var i=w.findIndex(function(x){return x.h===item.h;});var added;if(i>=0){w.splice(i,1);added=false;}else{w.unshift({h:item.h,t:item.t,p:Number(item.p),img:item.img});added=true;}wishSave(w);return added;}
function wishRemove(h){wishSave(wishGet().filter(function(x){return x.h!==h;}));}
function wishCount(){return wishGet().length;}
function wishBadge(){var n=wishCount();document.querySelectorAll('[title="account"]').forEach(function(s){s.classList.toggle('haswish',n>0);s.setAttribute('data-n',n||'');});}
function syncWishButtons(){document.querySelectorAll('.wish[data-h]').forEach(function(b){b.classList.toggle('on',wishHas(b.getAttribute('data-h')));});}
function wishEnsureDOM(){
  if(document.getElementById('wishDrawer'))return;
  var ov=document.createElement('div');ov.className='cart-ov';ov.id='wishOv';ov.hidden=true;ov.addEventListener('click',wishClose);
  var d=document.createElement('aside');d.className='cart-dr';d.id='wishDrawer';d.setAttribute('aria-hidden','true');d.setAttribute('role','dialog');d.setAttribute('aria-label','Wishlist');
  d.innerHTML='<div class="cd-top"><span class="cd-ttl serif"></span><button class="cd-x" type="button" aria-label="Close">✕</button></div><div class="cd-items" id="wiItems"></div>';
  document.body.appendChild(ov);document.body.appendChild(d);
  d.querySelector('.cd-x').addEventListener('click',wishClose);
  d.querySelector('#wiItems').addEventListener('click',function(e){
    var b=e.target.closest('[data-act]');if(!b)return;var h=b.getAttribute('data-h2');var act=b.getAttribute('data-act');
    if(act==='wrm')wishRemove(h);
    else if(act==='wadd'){var p=_catProd(h);if(p){cartAdd({h:p.h,t:p.t,p:p.p,img:(p.imgs&&p.imgs[0])||p.img,v:'',q:1});wishRemove(h);wishClose();}}
  });
}
function wishRender(){
  var d=document.getElementById('wishDrawer');if(!d)return;
  d.querySelector('.cd-ttl').textContent=cartT('wish_title');
  var items=d.querySelector('#wiItems');var w=wishGet();
  if(!w.length){items.innerHTML='<div class="cd-empty"><p>'+cartT('wish_empty')+'</p><a class="btn" href="collection.html">'+cartT('cart_empty_cta')+'</a></div>';return;}
  items.innerHTML=w.map(function(x){return '<div class="cd-item"><a href="product.html?p='+x.h+'"><img src="'+cartImg(x.img)+'" alt="" loading="lazy"></a><div class="cd-mid"><div class="cd-n serif"><a href="product.html?p='+x.h+'">'+x.t+'</a></div><div class="cd-qr"><button class="cd-rm" type="button" data-act="wadd" data-h2="'+x.h+'">'+cartT('wish_add')+'</button><button class="cd-rm" type="button" data-act="wrm" data-h2="'+x.h+'">'+cartT('cart_remove')+'</button></div></div><div class="cd-p">'+eurFmt(x.p)+'</div></div>';}).join('');
}
function wishOpen(){wishEnsureDOM();wishRender();var d=document.getElementById('wishDrawer'),ov=document.getElementById('wishOv');ov.hidden=false;void d.offsetWidth;d.classList.add('show');ov.classList.add('show');d.setAttribute('aria-hidden','false');document.body.style.overflow='hidden';}
function wishClose(){var d=document.getElementById('wishDrawer'),ov=document.getElementById('wishOv');if(!d)return;d.classList.remove('show');ov.classList.remove('show');d.setAttribute('aria-hidden','true');document.body.style.overflow='';setTimeout(function(){ov.hidden=true;},320);}
function initWish(){
  wishEnsureDOM();wishBadge();syncWishButtons();
  document.querySelectorAll('[title="account"]').forEach(function(s){s.style.cursor='pointer';s.addEventListener('click',wishOpen);});
  document.addEventListener('click',function(e){
    var b=e.target.closest('.wish[data-h]');if(!b)return;
    e.preventDefault();e.stopPropagation();
    var h=b.getAttribute('data-h');var p=_catProd(h);
    var item=p?{h:p.h,t:p.t,p:p.p,img:(p.imgs&&p.imgs[0])||p.img}:{h:h,t:b.getAttribute('data-t')||'Brush',p:Number(b.getAttribute('data-p'))||0,img:b.getAttribute('data-img')||''};
    var added=wishToggle(item);b.classList.toggle('on',added);
    if(added)cartToast(cartT('wish_added'));
  });
  window.wishRerender=wishRender;
}
function initCart(){
  cartEnsureDOM();cartBadge();
  document.querySelectorAll('[title="cart"]').forEach(function(s){s.style.cursor='pointer';s.addEventListener('click',cartOpen);});
  document.addEventListener('keydown',function(e){if(e.key==='Escape')cartClose();});
  /* PDP buy buttons */
  var h=new URLSearchParams(location.search).get('p');var pp=_catProd(h);
  if(pp){
    document.querySelectorAll('.buyrow .btn, .stickybar .btn').forEach(function(btn){
      btn.addEventListener('click',function(e){
        e.preventDefault();
        var qel=document.getElementById('q');var qty=qel?(parseInt(qel.textContent,10)||1):1;
        var onv=document.querySelector('.opt .row button.on');var variant=onv?onv.textContent.trim():'';
        cartAdd({h:pp.h,t:pp.t,p:pp.p,img:(pp.imgs&&pp.imgs[0])||pp.img,v:variant,q:qty},document.getElementById('mainimg'));
      });
    });
  }
  /* collection / related cards: the hover "add" overlay — delegated so it survives grid re-renders (filter/sort) */
  document.addEventListener('click',function(e){
      var add=e.target.closest('.prod .add');if(!add)return;
      e.preventDefault();e.stopPropagation();
      var card=add.closest('.prod');if(!card)return;
      var cim=card.querySelector('img');
      var href=card.getAttribute('href')||'';var m=href.match(/[?&]p=([^&]+)/);var hh=m?decodeURIComponent(m[1]):null;
      var p=_catProd(hh);
      if(p){cartAdd({h:p.h,t:p.t,p:p.p,img:(p.imgs&&p.imgs[0])||p.img,v:'',q:1},cim);return;}
      var t=(card.querySelector('h4')||{}).textContent||'Brush';
      var pr=parseFloat(card.getAttribute('data-price')||'0')||0;
      if(!pr){var px=card.querySelector('.px');if(px)pr=parseFloat((px.textContent||'').replace('€','').replace(',','.'))||0;}
      var im=(card.querySelector('img')||{}).src||'';
      cartAdd({h:href||t,t:t,p:pr,img:im,v:'',q:1},cim);
  });
  /* PDP bundle "add all three" */
  var bn=document.getElementById('bnbtn');
  if(bn){bn.addEventListener('click',function(){
    document.querySelectorAll('.bn-item').forEach(function(it,bi){
      var t=(it.querySelector('.bn-n')||{}).textContent||'Item';
      var pr=parseFloat(((it.querySelector('.bn-p')||{}).textContent||'').replace('€','').replace(',','.'))||0;
      var im=(it.querySelector('img')||{}).src||'';
      cartAdd({h:'bundle-'+t,t:t,p:pr,img:im,v:'',q:1},bi===0?it.querySelector('img'):null);
    });
  });}
}

/* ===== Mobile nav (hamburger + slide-down) — navlinks are display:none < 900px ===== */
function initNav(){
  var navrow=document.querySelector('nav .nav');var links=document.querySelector('.navlinks');var navright=document.querySelector('.navright');
  if(!navrow||!links||!navright||document.getElementById('mobnav'))return;
  var burger=document.createElement('button');
  burger.className='navburger';burger.type='button';burger.setAttribute('aria-label','Menu');burger.setAttribute('aria-expanded','false');burger.setAttribute('aria-controls','mobnav');
  burger.innerHTML='<span></span><span></span><span></span>';
  navright.insertBefore(burger,navright.firstChild);
  var panel=document.createElement('div');panel.className='mobnav';panel.id='mobnav';panel.hidden=true;
  panel.innerHTML='<div class="mobnav-in">'+links.innerHTML+'<a href="index.html" data-i="cl_home">Home</a><a href="our-story.html" data-i="sp_btn2">Our story</a></div>';
  document.querySelector('nav').appendChild(panel);
  function close(){panel.classList.remove('show');burger.classList.remove('on');burger.setAttribute('aria-expanded','false');setTimeout(function(){if(!panel.classList.contains('show'))panel.hidden=true;},260);}
  function open(){panel.hidden=false;void panel.offsetWidth;panel.classList.add('show');burger.classList.add('on');burger.setAttribute('aria-expanded','true');}
  burger.addEventListener('click',function(){if(panel.classList.contains('show'))close();else open();});
  panel.querySelectorAll('a').forEach(function(a){a.addEventListener('click',close);});
  window.addEventListener('resize',function(){if(window.innerWidth>900)close();});
}
